  ('social-worker-moex-02957', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '不同年代看待身心障礙者的觀點有所差異，認為身心障礙政策重點在所處的情境及生活環境的改善，而 非身心障礙者個人本質，此種觀點為：', '["個人模式", "關係模式", "權利模式", "社會模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02958', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為扶助特殊境遇家庭解決生活困難，協助其自立自強，我國特別訂定《特殊境遇家庭扶助條例》，該條例', '["子女生活津貼", "傷病醫療補助", "職業訓練生活補助", "創業貸款補助"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
