  ('social-worker-moex-02960', 'social-worker', 'social-worker-moex-102-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國96年身心障礙者保護法更名為「身心障礙者權益保障法」，下列那一項並非該法案重要的變革？', '["對身心障礙者的界定改由疾病別為主", "強調福利的取得必須經過需求評估", "由積極的福利取代消極的救助", "增加反歧視條款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "5309e5da3b72", "answer_pdf_sha1": "6eb405e0a872", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
